{
  "name": "GuardVision AI - Traffic Enforcement System",
  "description": "An advanced AI-powered traffic violation detection system optimizing for Indian vehicle formats and low-quality CCTV footage using Gemini Vision.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  TEAM_MEMBER = 'TEAM_MEMBER'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
}

export enum ViolationType {
  RED_LIGHT = 'Jumping Red Light',
  NO_HELMET = 'No Helmet',
  TRIPLE_RIDING = 'Triple Riding',
  WRONG_LANE = 'Wrong Lane Driving',
  ILLEGAL_PARKING = 'Illegal Parking',
  SPEEDING = 'Speeding'
}

export interface Violation {
  id: string;
  vehicleNumber: string;
  violationType: ViolationType;
  timestamp: string;
  location: string;
  mediaUrl: string;
  status: 'pending' | 'verified' | 'rejected';
  confidence: number;
  detectedBy: string;
}

export interface DetectionResult {
  vehicleNumber: string;
  violationType: ViolationType;
  confidence: number;
  reasoning: string;
}

import React from 'react';

export const APP_NAME = "GuardVision AI";
export const STORAGE_KEY_VIOLATIONS = 'guardvision_violations';
export const STORAGE_KEY_USERS = 'guardvision_users';
export const STORAGE_KEY_AUTH = 'guardvision_auth_user';

export const COLORS = {
  primary: '#2563eb', // Blue 600
  secondary: '#64748b', // Slate 500
  danger: '#dc2626', // Red 600
  success: '#16a34a', // Green 600
  warning: '#ca8a04', // Yellow 600
};

import { GoogleGenAI, Type } from "@google/genai";
import { DetectionResult, ViolationType } from "../types";

// In a real app, process.env.API_KEY is pre-configured.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const analyzeTrafficMedia = async (base64Media: string, mimeType: string): Promise<DetectionResult> => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are an expert Traffic Enforcement AI. Your task is to analyze traffic CCTV footage (images or videos).
    1. Detect vehicles and specifically identify Indian License Plate formats (e.g., MH 12 AB 1234, DL 3C AY 5678).
    2. Check for violations: Jumping red light, No helmet, Triple riding, Wrong lane driving, Illegal parking.
    3. Even if the quality is low (typical of CCTV), use context to infer characters on the number plate.
    4. If multiple vehicles are present, focus on the one most clearly committing a violation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [
        {
          parts: [
            { text: "Analyze this traffic media for violations and extract the vehicle number plate." },
            { inlineData: { data: base64Media, mimeType: mimeType } }
          ]
        }
      ],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            vehicleNumber: { type: Type.STRING, description: "Extracted vehicle number plate (Indian format preferred)" },
            violationType: { 
              type: Type.STRING, 
              enum: Object.values(ViolationType),
              description: "The specific type of traffic violation detected" 
            },
            confidence: { type: Type.NUMBER, description: "Confidence score from 0 to 1" },
            reasoning: { type: Type.STRING, description: "Short explanation of the detection" }
          },
          required: ["vehicleNumber", "violationType", "confidence", "reasoning"]
        }
      }
    });

    const resultText = response.text;
    if (!resultText) throw new Error("Empty response from AI");

    return JSON.parse(resultText) as DetectionResult;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import { Violation } from "../types";

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data:image/...;base64, prefix
      resolve(result.split(',')[1]);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const formatDateTime = (isoString: string) => {
  return new Date(isoString).toLocaleString('en-IN', {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
};

export const exportToCSV = (data: Violation[]) => {
  const headers = ['ID', 'Vehicle Number', 'Violation Type', 'Timestamp', 'Location', 'Status', 'Confidence'];
  const rows = data.map(v => [
    v.id,
    v.vehicleNumber,
    v.violationType,
    v.timestamp,
    v.location,
    v.status,
    v.confidence
  ]);

  const csvContent = [
    headers.join(','),
    ...rows.map(row => row.join(','))
  ].join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  const url = URL.createObjectURL(blob);
  link.setAttribute('href', url);
  link.setAttribute('download', `traffic_violations_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Upload, 
  History, 
  Users, 
  LogOut, 
  ShieldCheck, 
  AlertTriangle,
  FileDown,
  Menu,
  X
} from 'lucide-react';
import { User, UserRole, Violation, STORAGE_KEY_AUTH, STORAGE_KEY_VIOLATIONS } from './types';
import Dashboard from './components/Dashboard';
import UploadSection from './components/UploadSection';
import ViolationHistory from './components/ViolationHistory';
import UserManagement from './components/UserManagement';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'upload' | 'history' | 'admin'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  useEffect(() => {
    const savedUser = localStorage.getItem(STORAGE_KEY_AUTH);
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (role: UserRole) => {
    const mockUser: User = {
      id: role === UserRole.ADMIN ? '1' : '2',
      name: role === UserRole.ADMIN ? 'Administrator' : 'Field Officer',
      email: role === UserRole.ADMIN ? 'admin@guardvision.ai' : 'officer@guardvision.ai',
      role: role
    };
    setCurrentUser(mockUser);
    localStorage.setItem(STORAGE_KEY_AUTH, JSON.stringify(mockUser));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(STORAGE_KEY_AUTH);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full text-center">
          <div className="flex justify-center mb-6">
            <div className="bg-blue-100 p-4 rounded-full">
              <ShieldCheck className="w-12 h-12 text-blue-600" />
            </div>
          </div>
          <h1 className="text-2xl font-bold text-slate-900 mb-2">GuardVision AI</h1>
          <p className="text-slate-500 mb-8">Secure Traffic Enforcement Management System</p>

          <div className="space-y-4">
            <button 
              onClick={() => handleLogin(UserRole.ADMIN)}
              className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-semibold transition flex items-center justify-center gap-2"
            >
              <ShieldCheck className="w-5 h-5" />
              Login as Admin
            </button>
            <button 
              onClick={() => handleLogin(UserRole.TEAM_MEMBER)}
              className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-800 rounded-lg font-semibold transition flex items-center justify-center gap-2"
            >
              <Users className="w-5 h-5" />
              Login as Team Member
            </button>
          </div>
          <p className="mt-6 text-xs text-slate-400">Authorized Personnel Only</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar */}
      <aside className={`
        ${isSidebarOpen ? 'w-64' : 'w-20'} 
        bg-white border-r border-slate-200 transition-all duration-300 flex flex-col fixed inset-y-0 z-50
      `}>
        <div className="p-6 flex items-center gap-3">
          <ShieldCheck className="w-8 h-8 text-blue-600 shrink-0" />
          {isSidebarOpen && <span className="text-xl font-bold text-slate-800">GuardVision</span>}
        </div>

        <nav className="flex-1 px-4 space-y-2 mt-4">
          <NavItem 
            icon={<LayoutDashboard className="w-5 h-5" />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('dashboard')} 
          />
          <NavItem 
            icon={<Upload className="w-5 h-5" />} 
            label="Process Media" 
            active={activeTab === 'upload'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('upload')} 
          />
          <NavItem 
            icon={<History className="w-5 h-5" />} 
            label="Violation Logs" 
            active={activeTab === 'history'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('history')} 
          />
          {currentUser.role === UserRole.ADMIN && (
            <NavItem 
              icon={<Users className="w-5 h-5" />} 
              label="User Mgmt" 
              active={activeTab === 'admin'} 
              collapsed={!isSidebarOpen}
              onClick={() => setActiveTab('admin')} 
            />
          )}
        </nav>

        <div className="p-4 border-t border-slate-200">
          <div className="flex items-center gap-3 mb-4 px-2">
            <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 font-bold shrink-0">
              {currentUser.name[0]}
            </div>
            {isSidebarOpen && (
              <div className="overflow-hidden">
                <p className="text-sm font-medium text-slate-900 truncate">{currentUser.name}</p>
                <p className="text-xs text-slate-500 truncate">{currentUser.role}</p>
              </div>
            )}
          </div>
          <button 
            onClick={handleLogout}
            className="w-full py-2 flex items-center gap-3 px-2 text-slate-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition"
          >
            <LogOut className="w-5 h-5 shrink-0" />
            {isSidebarOpen && <span className="text-sm font-medium">Logout</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`${isSidebarOpen ? 'ml-64' : 'ml-20'} flex-1 min-h-screen transition-all duration-300 p-8`}>
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 capitalize">{activeTab}</h2>
            <p className="text-slate-500 text-sm">Welcome back, {currentUser.name}</p>
          </div>
          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="p-2 hover:bg-white rounded-lg shadow-sm border border-slate-200"
          >
            {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <Dashboard />}
          {activeTab === 'upload' && <UploadSection user={currentUser} />}
          {activeTab === 'history' && <ViolationHistory isAdmin={currentUser.role === UserRole.ADMIN} />}
          {activeTab === 'admin' && currentUser.role === UserRole.ADMIN && <UserManagement />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  collapsed: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, collapsed, onClick }) => (
  <button 
    onClick={onClick}
    className={`
      w-full flex items-center gap-3 p-3 rounded-xl transition-all
      ${active 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
        : 'text-slate-600 hover:bg-slate-100'
      }
    `}
  >
    <span className="shrink-0">{icon}</span>
    {!collapsed && <span className="font-medium">{label}</span>}
  </button>
);

export default App;

import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';
import { AlertTriangle, Car, CheckCircle, Clock } from 'lucide-react';
import { Violation, STORAGE_KEY_VIOLATIONS, ViolationType } from '../types';

const Dashboard: React.FC = () => {
  const violations: Violation[] = useMemo(() => {
    const data = localStorage.getItem(STORAGE_KEY_VIOLATIONS);
    return data ? JSON.parse(data) : [];
  }, []);

  const stats = useMemo(() => {
    const total = violations.length;
    const pending = violations.filter(v => v.status === 'pending').length;
    const verified = violations.filter(v => v.status === 'verified').length;
    const rejected = violations.filter(v => v.status === 'rejected').length;

    // Violation type breakdown
    const typeBreakdown = Object.values(ViolationType).map(type => ({
      name: type,
      value: violations.filter(v => v.violationType === type).length
    })).filter(item => item.value > 0);

    return { total, pending, verified, rejected, typeBreakdown };
  }, [violations]);

  const COLORS = ['#2563eb', '#7c3aed', '#db2777', '#ea580c', '#ca8a04', '#16a34a'];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={<AlertTriangle className="text-amber-600" />} 
          title="Total Violations" 
          value={stats.total} 
          trend="+12% from last week"
        />
        <StatCard 
          icon={<Clock className="text-blue-600" />} 
          title="Pending Review" 
          value={stats.pending} 
          trend="Action required"
        />
        <StatCard 
          icon={<CheckCircle className="text-green-600" />} 
          title="Verified" 
          value={stats.verified} 
          trend="89% validation rate"
        />
        <StatCard 
          icon={<Car className="text-slate-600" />} 
          title="Active Vehicles" 
          value={new Set(violations.map(v => v.vehicleNumber)).size} 
          trend="Unique IDs detected"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Violations by Type</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.typeBreakdown}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" tick={{fontSize: 12}} stroke="#94a3b8" />
                <YAxis tick={{fontSize: 12}} stroke="#94a3b8" />
                <Tooltip 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}}
                />
                <Bar dataKey="value" fill="#2563eb" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Enforcement Status</h3>
          <div className="h-80 flex items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={[
                    { name: 'Pending', value: stats.pending },
                    { name: 'Verified', value: stats.verified },
                    { name: 'Rejected', value: stats.rejected },
                  ]}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.typeBreakdown.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="w-1/3 space-y-2">
              <LegendItem color={COLORS[0]} label="Pending" value={stats.pending} />
              <LegendItem color={COLORS[1]} label="Verified" value={stats.verified} />
              <LegendItem color={COLORS[2]} label="Rejected" value={stats.rejected} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, title: string, value: number, trend: string }> = ({ icon, title, value, trend }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
    <div className="flex justify-between items-start mb-4">
      <div className="p-3 bg-slate-50 rounded-xl">{icon}</div>
      <span className="text-xs font-medium text-slate-400 bg-slate-50 px-2 py-1 rounded-full">{trend}</span>
    </div>
    <p className="text-slate-500 text-sm font-medium">{title}</p>
    <h4 className="text-3xl font-bold text-slate-900 mt-1">{value}</h4>
  </div>
);

const LegendItem: React.FC<{ color: string, label: string, value: number }> = ({ color, label, value }) => (
  <div className="flex items-center gap-2">
    <div className="w-3 h-3 rounded-full" style={{ backgroundColor: color }}></div>
    <span className="text-sm text-slate-600">{label} ({value})</span>
  </div>
);

export default Dashboard;

import React, { useState, useRef } from 'react';
import { Upload, Camera, FileVideo, X, CheckCircle2, AlertCircle, Loader2 } from 'lucide-react';
import { User, Violation, STORAGE_KEY_VIOLATIONS } from '../types';
import { analyzeTrafficMedia } from '../services/geminiService';
import { fileToBase64 } from '../utils/helpers';

interface UploadSectionProps {
  user: User;
}

const UploadSection: React.FC<UploadSectionProps> = ({ user }) => {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<Violation | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
      setResult(null);
      setError(null);
    }
  };

  const processMedia = async () => {
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      const base64Data = await fileToBase64(file);
      const mimeType = file.type;

      const aiResult = await analyzeTrafficMedia(base64Data, mimeType);

      const newViolation: Violation = {
        id: Math.random().toString(36).substr(2, 9),
        vehicleNumber: aiResult.vehicleNumber,
        violationType: aiResult.violationType,
        timestamp: new Date().toISOString(),
        location: 'Sector 45, Highway CCTV Camera 04', // Mocked location
        mediaUrl: preview || '',
        status: 'pending',
        confidence: aiResult.confidence,
        detectedBy: user.name
      };

      // Save to local storage
      const existing = localStorage.getItem(STORAGE_KEY_VIOLATIONS);
      const violations = existing ? JSON.parse(existing) : [];
      violations.unshift(newViolation);
      localStorage.setItem(STORAGE_KEY_VIOLATIONS, JSON.stringify(violations));

      setResult(newViolation);
    } catch (err: any) {
      console.error(err);
      setError("AI Processing failed. Ensure the image clearly shows a vehicle and number plate.");
    } finally {
      setIsProcessing(false);
    }
  };

  const reset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className={`
        bg-white border-2 border-dashed rounded-3xl p-12 transition-all text-center
        ${file ? 'border-blue-400' : 'border-slate-200 hover:border-blue-300'}
      `}>
        {!file ? (
          <div className="space-y-4">
            <div className="bg-blue-50 w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-6">
              <Upload className="w-10 h-10 text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Upload CCTV Media</h3>
            <p className="text-slate-500 max-w-md mx-auto">
              Select footage from traffic cameras. Supported formats: JPG, PNG, MP4. 
              Optimized for low-light Indian number plate formats.
            </p>
            <div className="pt-4">
              <input 
                type="file" 
                ref={fileInputRef}
                className="hidden" 
                accept="image/*,video/*"
                onChange={handleFileChange}
              />
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition shadow-lg shadow-blue-100"
              >
                Browse Files
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="relative inline-block max-w-full overflow-hidden rounded-2xl border border-slate-200 shadow-xl bg-slate-100">
              {file.type.startsWith('image/') ? (
                <img src={preview!} alt="Preview" className="max-h-[400px] w-auto object-contain" />
              ) : (
                <video src={preview!} className="max-h-[400px]" controls />
              )}
              <button 
                onClick={reset}
                className="absolute top-4 right-4 p-2 bg-white/80 hover:bg-white text-slate-900 rounded-full transition shadow-lg backdrop-blur-sm"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {!result && (
              <div className="flex justify-center gap-4">
                <button 
                  onClick={processMedia}
                  disabled={isProcessing}
                  className={`
                    px-8 py-3 rounded-xl font-bold transition flex items-center gap-3
                    ${isProcessing 
                      ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                      : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-100'
                    }
                  `}
                >
                  {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldCheck className="w-5 h-5" />}
                  {isProcessing ? 'Analyzing Frame...' : 'Detect Violations'}
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-4 text-red-700">
          <AlertCircle className="shrink-0" />
          <p className="text-sm font-medium">{error}</p>
        </div>
      )}

      {result && (
        <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex items-center gap-3 mb-6 text-green-600">
            <CheckCircle2 className="w-6 h-6" />
            <h3 className="text-xl font-bold">Analysis Complete</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <ResultItem label="Vehicle Plate" value={result.vehicleNumber} highlight />
            <ResultItem label="Violation Type" value={result.violationType} color="text-red-600" />
            <ResultItem label="AI Confidence" value={`${(result.confidence * 100).toFixed(1)}%`} />
          </div>

          <div className="mt-8 pt-8 border-t border-slate-100 flex items-center justify-between">
            <p className="text-slate-500 text-sm">
