          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search by vehicle number..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition"
          />
        </div>

        <div className="flex items-center gap-3">
          <div className="relative">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <select 
              className="pl-10 pr-8 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm appearance-none focus:outline-none transition"
              value={filterType}
              onChange={(e) => setFilterType(e.target.value)}
            >
              <option value="all">All Types</option>
              {Object.values(ViolationType).map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>

          <button 
            onClick={() => exportToCSV(violations)}
            className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-sm font-semibold hover:bg-slate-800 transition"
          >
            <FileDown className="w-4 h-4" />
            Export CSV
          </button>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Vehicle Details</th>
              <th className="px-6 py-4">Violation</th>
              <th className="px-6 py-4">Time & Location</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4">Confidence</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredViolations.length > 0 ? filteredViolations.map((violation) => (
              <tr key={violation.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-lg bg-slate-100 flex items-center justify-center shrink-0">
                      <Eye className="w-5 h-5 text-slate-400" />
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">{violation.vehicleNumber}</p>
                      <p className="text-xs text-slate-400 italic">Plate # ID: {violation.id}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className={`
                    px-2.5 py-0.5 rounded-full text-xs font-bold
                    ${violation.violationType === ViolationType.RED_LIGHT ? 'bg-red-100 text-red-700' : 'bg-orange-100 text-orange-700'}
                  `}>
                    {violation.violationType}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <p className="text-sm font-medium text-slate-700">{formatDateTime(violation.timestamp)}</p>
                  <p className="text-xs text-slate-400">{violation.location}</p>
                </td>
                <td className="px-6 py-4">
                  <span className={`
                    inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-semibold
                    ${violation.status === 'verified' ? 'bg-green-50 text-green-700 border border-green-100' : 
                      violation.status === 'rejected' ? 'bg-red-50 text-red-700 border border-red-100' : 
                      'bg-slate-100 text-slate-700 border border-slate-200'}
                  `}>
                    <div className={`w-1.5 h-1.5 rounded-full ${
                      violation.status === 'verified' ? 'bg-green-500' : 
                      violation.status === 'rejected' ? 'bg-red-500' : 'bg-slate-400'
                    }`} />
                    {violation.status.charAt(0).toUpperCase() + violation.status.slice(1)}
