  const [activeTab, setActiveTab] = useState<'dashboard' | 'upload' | 'history' | 'admin'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  useEffect(() => {
    const savedUser = localStorage.getItem(STORAGE_KEY_AUTH);
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (role: UserRole) => {
    const mockUser: User = {
      id: role === UserRole.ADMIN ? '1' : '2',
      name: role === UserRole.ADMIN ? 'Administrator' : 'Field Officer',
      email: role === UserRole.ADMIN ? 'admin@violatorvision.ai' : 'officer@violatorvision.ai',
      role: role
    };
    setCurrentUser(mockUser);
    localStorage.setItem(STORAGE_KEY_AUTH, JSON.stringify(mockUser));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(STORAGE_KEY_AUTH);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full text-center">
          <div className="flex justify-center mb-6">
            <div className="bg-blue-100 p-4 rounded-full">
              <ShieldCheck className="w-12 h-12 text-blue-600" />
            </div>
          </div>
          <h1 className="text-2xl font-bold text-slate-900 mb-2">{APP_NAME}</h1>
          <p className="text-slate-500 mb-8">Secure Traffic Enforcement Management System</p>

          <div className="space-y-4">
            <button 
              onClick={() => handleLogin(UserRole.ADMIN)}
              className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-semibold transition flex items-center justify-center gap-2"
            >
              <ShieldCheck className="w-5 h-5" />
              Login as Admin
            </button>
            <button 
              onClick={() => handleLogin(UserRole.TEAM_MEMBER)}
              className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-800 rounded-lg font-semibold transition flex items-center justify-center gap-2"
            >
              <Users className="w-5 h-5" />
              Login as Team Member
            </button>
          </div>
          <p className="mt-6 text-xs text-slate-400">Authorized Personnel Only</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar */}
      <aside className={`
        ${isSidebarOpen ? 'w-64' : 'w-20'} 
        bg-white border-r border-slate-200 transition-all duration-300 flex flex-col fixed inset-y-0 z-50
      `}>
        <div className="p-6 flex items-center gap-3">
          <ShieldCheck className="w-8 h-8 text-blue-600 shrink-0" />
          {isSidebarOpen && <span className="text-xl font-bold text-slate-800">{APP_NAME}</span>}
        </div>

        <nav className="flex-1 px-4 space-y-2 mt-4">
          <NavItem 
            icon={<LayoutDashboard className="w-5 h-5" />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('dashboard')} 
          />
          <NavItem 
            icon={<Upload className="w-5 h-5" />} 
            label="Process Media" 
            active={activeTab === 'upload'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('upload')} 
          />
          <NavItem 
            icon={<History className="w-5 h-5" />} 
            label="Violation Logs" 
            active={activeTab === 'history'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('history')} 
          />
          {currentUser.role === UserRole.ADMIN && (
            <NavItem 
              icon={<Users className="w-5 h-5" />} 
              label="User Mgmt" 
              active={activeTab === 'admin'} 
              collapsed={!isSidebarOpen}
              onClick={() => setActiveTab('admin')} 
            />
          )}
        </nav>

        <div className="p-4 border-t border-slate-200">
          <div className="flex items-center gap-3 mb-4 px-2">
            <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 font-bold shrink-0">
              {currentUser.name[0]}
            </div>
            {isSidebarOpen && (
              <div className="overflow-hidden">
                <p className="text-sm font-medium text-slate-900 truncate">{currentUser.name}</p>
                <p className="text-xs text-slate-500 truncate">{currentUser.role}</p>
              </div>
            )}
          </div>
          <button 
            onClick={handleLogout}
            className="w-full py-2 flex items-center gap-3 px-2 text-slate-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition"
          >
            <LogOut className="w-5 h-5 shrink-0" />
            {isSidebarOpen && <span className="text-sm font-medium">Logout</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`${isSidebarOpen ? 'ml-64' : 'ml-20'} flex-1 min-h-screen transition-all duration-300 p-8`}>
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 capitalize">{activeTab}</h2>
            <p className="text-slate-500 text-sm">Welcome back, {currentUser.name}</p>
          </div>
          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="p-2 hover:bg-white rounded-lg shadow-sm border border-slate-200"
          >
            {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <Dashboard />}
          {activeTab === 'upload' && <UploadSection user={currentUser} />}
          {activeTab === 'history' && <ViolationHistory isAdmin={currentUser.role === UserRole.ADMIN} />}
          {activeTab === 'admin' && currentUser.role === UserRole.ADMIN && <UserManagement />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  collapsed: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, collapsed, onClick }) => (
  <button 
    onClick={onClick}
    className={`
      w-full flex items-center gap-3 p-3 rounded-xl transition-all
      ${active 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
        : 'text-slate-600 hover:bg-slate-100'
      }
    `}
  >
    <span className="shrink-0">{icon}</span>
    {!collapsed && <span className="font-medium">{label}</span>}
  </button>
);

export default App;

export enum UserRole {
  ADMIN = 'ADMIN',
  TEAM_MEMBER = 'TEAM_MEMBER'
}

export interface User {
  id: string; // acts as User ID or Phone Number
  name: string;
  email: string;
  role: UserRole;
  password?: string; // Optional because we don't want it in the active session object
}

export enum ViolationType {
  RED_LIGHT = 'Jumping Red Light',
  NO_HELMET = 'No Helmet',
  TRIPLE_RIDING = 'Triple Riding',
  WRONG_LANE = 'Wrong Lane Driving',
  ILLEGAL_PARKING = 'Illegal Parking',
  SPEEDING = 'Speeding'
}

export interface Violation {
  id: string;
  vehicleNumber: string;
  violationType: ViolationType;
  timestamp: string;
  location: string;
  mediaUrl: string;
  status: 'pending' | 'verified' | 'rejected';
  confidence: number;
  detectedBy: string;
}

export interface DetectionResult {
  vehicleNumber: string;
  violationType: ViolationType;
  confidence: number;
  reasoning: string;
}

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Upload, 
  History, 
  Users, 
  LogOut, 
  ShieldCheck, 
  AlertTriangle,
  FileDown,
  Menu,
  X,
  Lock,
  User as UserIcon,
  Smartphone,
  ChevronRight
} from 'lucide-react';
import { User, UserRole, Violation } from './types';
import { STORAGE_KEY_AUTH, STORAGE_KEY_VIOLATIONS, STORAGE_KEY_USERS, APP_NAME } from './constants';
import Dashboard from './components/Dashboard';
import UploadSection from './components/UploadSection';
import ViolationHistory from './components/ViolationHistory';
import UserManagement from './components/UserManagement';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'upload' | 'history' | 'admin'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isLoginView, setIsLoginView] = useState(true);

  // Login form states
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    // Initialize default admin if no users exist
    const storedUsers = localStorage.getItem(STORAGE_KEY_USERS);
    if (!storedUsers) {
      const defaultAdmin: User = {
        id: 'admin',
        name: 'System Administrator',
        email: 'admin@violatorvision.ai',
        role: UserRole.ADMIN,
        password: 'password123'
      };
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify([defaultAdmin]));
    }

    const savedUser = localStorage.getItem(STORAGE_KEY_AUTH);
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const storedUsers: User[] = JSON.parse(localStorage.getItem(STORAGE_KEY_USERS) || '[]');
    const user = storedUsers.find(u => u.id === loginId && u.password === password);

    if (user) {
      const { password, ...sessionUser } = user;
      setCurrentUser(sessionUser);
      localStorage.setItem(STORAGE_KEY_AUTH, JSON.stringify(sessionUser));
    } else {
      setError('Invalid User ID or Password. Try admin / password123');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(STORAGE_KEY_AUTH);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl p-8 max-w-md w-full relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-blue-600"></div>

          <div className="text-center mb-8">
            <div className="flex justify-center mb-4">
              <div className="bg-blue-50 p-4 rounded-2xl">
                <ShieldCheck className="w-10 h-10 text-blue-600" />
              </div>
            </div>
            <h1 className="text-2xl font-bold text-slate-900 mb-1">{APP_NAME}</h1>
            <p className="text-slate-500 text-sm italic">Traffic Enforcement Registry</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">User ID / Phone Number</label>
              <div className="relative">
                <Smartphone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="text" 
                  value={loginId}
                  onChange={(e) => setLoginId(e.target.value)}
                  placeholder="e.g. admin or 9876543210"
                  className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
                  required
                />
              </div>
            </div>

            {error && (
              <div className="p-3 bg-red-50 text-red-600 text-xs font-medium rounded-lg border border-red-100 flex items-center gap-2">
                <AlertTriangle className="w-4 h-4" />
                {error}
              </div>
            )}

            <button 
              type="submit"
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all shadow-lg shadow-blue-200 flex items-center justify-center gap-2 group"
            >
              Sign In
              <ChevronRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
            <p className="text-xs text-slate-400">
              Only authorized personnel can access this portal.<br/> 
              Contact administrator for new registrations.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar */}
      <aside className={`
        ${isSidebarOpen ? 'w-64' : 'w-20'} 
        bg-white border-r border-slate-200 transition-all duration-300 flex flex-col fixed inset-y-0 z-50 shadow-sm
      `}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-blue-600 p-1.5 rounded-lg shrink-0">
            <ShieldCheck className="w-6 h-6 text-white" />
          </div>
          {isSidebarOpen && <span className="text-xl font-bold text-slate-800 tracking-tight">{APP_NAME}</span>}
        </div>

        <nav className="flex-1 px-4 space-y-1.5 mt-4">
          <NavItem 
            icon={<LayoutDashboard className="w-5 h-5" />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('dashboard')} 
          />
          <NavItem 
            icon={<Upload className="w-5 h-5" />} 
            label="Media Lab" 
            active={activeTab === 'upload'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('upload')} 
          />
          <NavItem 
            icon={<History className="w-5 h-5" />} 
            label="Violation Hub" 
            active={activeTab === 'history'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('history')} 
          />
          {currentUser.role === UserRole.ADMIN && (
            <NavItem 
              icon={<Users className="w-5 h-5" />} 
              label="Staff Directory" 
              active={activeTab === 'admin'} 
              collapsed={!isSidebarOpen}
              onClick={() => setActiveTab('admin')} 
            />
          )}
        </nav>

        <div className="p-4 border-t border-slate-100">
          <div className="flex items-center gap-3 mb-4 px-2 bg-slate-50 p-2 rounded-xl border border-slate-200/50">
            <div className="w-9 h-9 rounded-lg bg-blue-600 flex items-center justify-center text-white font-bold shrink-0 shadow-sm">
              {currentUser.name[0]}
            </div>
            {isSidebarOpen && (
              <div className="overflow-hidden">
                <p className="text-sm font-bold text-slate-900 truncate leading-tight">{currentUser.name}</p>
                <p className="text-[10px] uppercase font-bold text-blue-600 tracking-wider">{currentUser.role}</p>
              </div>
            )}
          </div>
          <button 
            onClick={handleLogout}
            className="w-full py-2 flex items-center gap-3 px-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
          >
            <LogOut className="w-5 h-5 shrink-0" />
            {isSidebarOpen && <span className="text-sm font-medium">Log Out</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`${isSidebarOpen ? 'ml-64' : 'ml-20'} flex-1 min-h-screen transition-all duration-300 p-8`}>
        <header className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-4">
             <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2 hover:bg-white rounded-xl shadow-sm border border-slate-200 bg-white"
            >
              {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
            </button>
            <div>
              <h2 className="text-2xl font-bold text-slate-800 capitalize tracking-tight">{activeTab.replace('admin', 'Staff Management')}</h2>
              <p className="text-slate-400 text-xs font-medium uppercase tracking-widest mt-0.5">Automated Traffic Vigilance</p>
            </div>
          </div>

          <div className="flex items-center gap-3 bg-white p-1.5 pr-4 rounded-2xl border border-slate-200 shadow-sm">
            <div className="w-8 h-8 rounded-xl bg-slate-100 flex items-center justify-center">
              <UserIcon className="w-4 h-4 text-slate-500" />
            </div>
            <span className="text-sm font-semibold text-slate-700">{currentUser.name}</span>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <Dashboard />}
          {activeTab === 'upload' && <UploadSection user={currentUser} />}
          {activeTab === 'history' && <ViolationHistory isAdmin={currentUser.role === UserRole.ADMIN} />}
          {activeTab === 'admin' && currentUser.role === UserRole.ADMIN && <UserManagement />}
        </div>
      </main>
    </div>
  );
};

