import React, { useState, useEffect } from 'react';
import { UserPlus, Search, UserCheck, Shield, Trash2, X, Lock, Smartphone, Mail, User as UserIcon } from 'lucide-react';
import { User, UserRole } from '../types';
import { STORAGE_KEY_USERS } from '../constants';

const UserManagement: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form states
  const [formData, setFormData] = useState({
    id: '',
    name: '',
    email: '',
    password: '',
    role: UserRole.TEAM_MEMBER
  });

  useEffect(() => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (data) {
      setUsers(JSON.parse(data));
    }
  }, []);

  const handleDelete = (id: string) => {
    if (id === 'admin') {
      alert("Primary admin cannot be removed.");
      return;
    }
    if (confirm("Are you sure you want to remove this user's access?")) {
      const updated = users.filter(u => u.id !== id);
      setUsers(updated);
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(updated));
    }
  };

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (users.some(u => u.id === formData.id)) {
      alert("A user with this ID/Phone number already exists.");
      return;
    }

    const newUser: User = { ...formData };
    const updatedUsers = [...users, newUser];
    setUsers(updatedUsers);
    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(updatedUsers));
    setShowAddModal(false);
    setFormData({ id: '', name: '', email: '', password: '', role: UserRole.TEAM_MEMBER });
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search team members by name or ID..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-2xl shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition"
          />
        </div>

        <button 
          onClick={() => setShowAddModal(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-100 transition"
        >
          <UserPlus className="w-5 h-5" />
          Register New Staff
        </button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider border-b border-slate-100">
            <tr>
              <th className="px-6 py-4">Staff Details</th>
              <th className="px-6 py-4">Role / Access</th>
              <th className="px-6 py-4">System ID</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredUsers.map((user) => (
              <tr key={user.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center font-bold text-blue-600 shadow-sm border border-blue-100">
                      {user.name[0]}
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">{user.name}</p>
                      <p className="text-xs text-slate-400 font-medium">{user.email}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2">
                    {user.role === UserRole.ADMIN ? (
                      <Shield className="w-4 h-4 text-blue-600" />
                    ) : (
                      <UserCheck className="w-4 h-4 text-slate-400" />
                    )}
                    <span className={`text-xs font-bold uppercase tracking-wider ${user.role === UserRole.ADMIN ? 'text-blue-600' : 'text-slate-500'}`}>
                      {user.role}
                    </span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm font-mono bg-slate-100 px-2 py-1 rounded text-slate-600 border border-slate-200">
                    {user.id}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <span className="px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-widest bg-green-50 text-green-700 border border-green-100">
                    Active
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  <button 
                    onClick={() => handleDelete(user.id)}
                    disabled={user.id === 'admin'}
                    className={`p-2 rounded-xl transition-all ${user.id === 'admin' ? 'text-slate-200 cursor-not-allowed' : 'text-slate-400 hover:text-red-600 hover:bg-red-50'}`}
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Add User Modal */}
