import React, { useState, useRef } from 'react';
import { Upload, Camera, FileVideo, X, CheckCircle2, AlertCircle, Loader2, ShieldCheck } from 'lucide-react';
import { User, Violation } from '../types';
import { STORAGE_KEY_VIOLATIONS } from '../constants';
import { analyzeTrafficMedia } from '../services/geminiService';
import { fileToBase64 } from '../utils/helpers';

interface UploadSectionProps {
  user: User;
}

const UploadSection: React.FC<UploadSectionProps> = ({ user }) => {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<Violation | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
      setResult(null);
      setError(null);
    }
  };

  const processMedia = async () => {
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      const base64Data = await fileToBase64(file);
      const mimeType = file.type;

      const aiResult = await analyzeTrafficMedia(base64Data, mimeType);

      const newViolation: Violation = {
        id: Math.random().toString(36).substr(2, 9),
        vehicleNumber: aiResult.vehicleNumber,
        violationType: aiResult.violationType,
        timestamp: new Date().toISOString(),
        location: 'Traffic Sector Unit 04', // Mocked location source
        mediaUrl: preview || '',
        status: 'pending',
        confidence: aiResult.confidence,
        detectedBy: user.name
      };

      // Save to local storage
      const existing = localStorage.getItem(STORAGE_KEY_VIOLATIONS);
      const violations = existing ? JSON.parse(existing) : [];
      violations.unshift(newViolation);
      localStorage.setItem(STORAGE_KEY_VIOLATIONS, JSON.stringify(violations));

      setResult(newViolation);
    } catch (err: any) {
      console.error(err);
      setError("AI Processing failed. Ensure the image clearly shows a vehicle and number plate.");
    } finally {
      setIsProcessing(false);
    }
  };

  const reset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className={`
        bg-white border-2 border-dashed rounded-3xl p-12 transition-all text-center
        ${file ? 'border-blue-400' : 'border-slate-200 hover:border-blue-300'}
      `}>
        {!file ? (
          <div className="space-y-4">
            <div className="bg-blue-50 w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-6">
              <Upload className="w-10 h-10 text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-800">CCTV Media Upload</h3>
            <p className="text-slate-500 max-w-md mx-auto">
              Select footage from traffic cameras. Supported formats: JPG, PNG, MP4. 
              Optimized for night-vision and low-quality Indian license plates.
            </p>
            <div className="pt-4">
              <input 
                type="file" 
                ref={fileInputRef}
                className="hidden" 
                accept="image/*,video/*"
                onChange={handleFileChange}
              />
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition shadow-lg shadow-blue-100"
              >
                Select File
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="relative inline-block max-w-full overflow-hidden rounded-2xl border border-slate-200 shadow-xl bg-slate-100">
              {file.type.startsWith('image/') ? (
                <img src={preview!} alt="Preview" className="max-h-[400px] w-auto object-contain" />
              ) : (
                <video src={preview!} className="max-h-[400px]" controls />
              )}
              <button 
                onClick={reset}
                className="absolute top-4 right-4 p-2 bg-white/80 hover:bg-white text-slate-900 rounded-full transition shadow-lg backdrop-blur-sm"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {!result && (
              <div className="flex justify-center gap-4">
                <button 
                  onClick={processMedia}
                  disabled={isProcessing}
                  className={`
                    px-8 py-3 rounded-xl font-bold transition flex items-center gap-3
                    ${isProcessing 
                      ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                      : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-100'
                    }
                  `}
                >
                  {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldCheck className="w-5 h-5" />}
                  {isProcessing ? 'Analyzing Content...' : 'Verify Violation'}
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-4 text-red-700">
          <AlertCircle className="shrink-0" />
          <p className="text-sm font-medium">{error}</p>
        </div>
      )}

      {result && (
        <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex items-center gap-3 mb-6 text-green-600">
            <CheckCircle2 className="w-6 h-6" />
            <h3 className="text-xl font-bold">Automatic Detection Logged</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <ResultItem label="Identified Plate" value={result.vehicleNumber} highlight />
            <ResultItem label="Violation Category" value={result.violationType} color="text-red-600" />
            <ResultItem label="System Confidence" value={`${(result.confidence * 100).toFixed(1)}%`} />
          </div>

          <div className="mt-8 pt-8 border-t border-slate-100 flex items-center justify-between">
            <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">
              Recorded by {result.detectedBy} @ {new Date(result.timestamp).toLocaleTimeString()}
            </p>
            <button 
              onClick={reset}
              className="text-blue-600 font-bold hover:underline"
            >
              Analyze Another
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

const ResultItem: React.FC<{ label: string, value: string, highlight?: boolean, color?: string }> = ({ label, value, highlight, color }) => (
  <div className="space-y-1">
    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{label}</p>
    <p className={`text-xl font-bold ${color || 'text-slate-900'} ${highlight ? 'bg-slate-50 px-3 py-1 rounded-lg border border-slate-200 inline-block' : ''}`}>
      {value}
    </p>
  </div>
);

export default UploadSection;

