type Theme = 'light' | 'dark' | 'system';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'upload' | 'history' | 'admin'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [theme, setTheme] = useState<Theme>((localStorage.getItem('violator_vision_theme') as Theme) || 'system');

  // Login form states
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Handle Theme Application
  useEffect(() => {
    const root = window.document.documentElement;
    const applyTheme = (t: Theme) => {
      root.classList.remove('light', 'dark');
      if (t === 'system') {
        const systemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
        root.classList.add(systemDark ? 'dark' : 'light');
      } else {
        root.classList.add(t);
      }
      localStorage.setItem('violator_vision_theme', t);
    };

    applyTheme(theme);

    // Listen for system changes if in system mode
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = () => {
      if (theme === 'system') applyTheme('system');
    };
    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, [theme]);

  useEffect(() => {
    const storedUsers = localStorage.getItem(STORAGE_KEY_USERS);
    if (!storedUsers) {
      const defaultAdmin: User = {
        id: 'admin',
        name: 'System Administrator',
        email: 'admin@violatorvision.ai',
        role: UserRole.ADMIN,
        password: 'password123'
      };
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify([defaultAdmin]));
    }

    const savedUser = localStorage.getItem(STORAGE_KEY_AUTH);
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const storedUsers: User[] = JSON.parse(localStorage.getItem(STORAGE_KEY_USERS) || '[]');
    const user = storedUsers.find(u => u.id === loginId && u.password === password);

    if (user) {
      const { password, ...sessionUser } = user;
      setCurrentUser(sessionUser);
      localStorage.setItem(STORAGE_KEY_AUTH, JSON.stringify(sessionUser));
    } else {
      setError('Invalid User ID or Password. Try admin / password123');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(STORAGE_KEY_AUTH);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 dark:bg-black flex items-center justify-center p-4 transition-colors duration-500">
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl p-8 max-w-md w-full relative overflow-hidden border border-slate-200 dark:border-slate-800">
          <div className="absolute top-0 left-0 w-full h-2 bg-blue-600"></div>

          <div className="text-center mb-8">
            <div className="flex justify-center mb-4">
              <div className="bg-blue-50 dark:bg-blue-900/30 p-4 rounded-2xl">
                <ShieldCheck className="w-10 h-10 text-blue-600 dark:text-blue-400" />
              </div>
            </div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-1">{APP_NAME}</h1>
            <p className="text-slate-500 dark:text-slate-400 text-sm italic">Traffic Enforcement Registry</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">User ID / Phone Number</label>
              <div className="relative">
                <Smartphone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="text" 
                  value={loginId}
                  onChange={(e) => setLoginId(e.target.value)}
                  placeholder="e.g. admin"
                  className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all dark:text-white"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all dark:text-white"
                  required
                />
              </div>
            </div>

            {error && (
              <div className="p-3 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-xs font-medium rounded-lg border border-red-100 dark:border-red-900/30 flex items-center gap-2">
                <AlertTriangle className="w-4 h-4" />
                {error}
              </div>
            )}

            <button 
              type="submit"
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all shadow-lg shadow-blue-200 dark:shadow-none flex items-center justify-center gap-2 group"
            >
              Sign In
              <ChevronRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500">
              Only authorized personnel can access this portal.<br/> 
              Contact administrator for new registrations.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      {/* Sidebar */}
      <aside className={`
        ${isSidebarOpen ? 'w-64' : 'w-20'} 
        bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transition-all duration-300 flex flex-col fixed inset-y-0 z-50 shadow-sm
      `}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-blue-600 p-1.5 rounded-lg shrink-0">
            <ShieldCheck className="w-6 h-6 text-white" />
          </div>
          {isSidebarOpen && <span className="text-xl font-bold text-slate-800 dark:text-white tracking-tight">{APP_NAME}</span>}
        </div>

        <nav className="flex-1 px-4 space-y-1.5 mt-4">
          <NavItem 
            icon={<LayoutDashboard className="w-5 h-5" />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('dashboard')} 
          />
          <NavItem 
            icon={<Upload className="w-5 h-5" />} 
            label="Media Lab" 
            active={activeTab === 'upload'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('upload')} 
          />
          <NavItem 
            icon={<History className="w-5 h-5" />} 
            label="Violation Hub" 
            active={activeTab === 'history'} 
            collapsed={!isSidebarOpen}
            onClick={() => setActiveTab('history')} 
          />
          {currentUser.role === UserRole.ADMIN && (
            <NavItem 
              icon={<Users className="w-5 h-5" />} 
              label="Staff Directory" 
              active={activeTab === 'admin'} 
              collapsed={!isSidebarOpen}
              onClick={() => setActiveTab('admin')} 
            />
          )}
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800 space-y-4">
          {/* Theme Switcher */}
          <div className={`flex ${isSidebarOpen ? 'justify-between' : 'justify-center'} bg-slate-100 dark:bg-slate-800 p-1 rounded-xl`}>
            <button 
              onClick={() => setTheme('light')}
              className={`p-2 rounded-lg transition-all ${theme === 'light' ? 'bg-white dark:bg-slate-700 text-blue-600 shadow-sm' : 'text-slate-500'}`}
              title="Light Mode"
            >
              <Sun className="w-4 h-4" />
            </button>
            <button 
              onClick={() => setTheme('system')}
              className={`p-2 rounded-lg transition-all ${theme === 'system' ? 'bg-white dark:bg-slate-700 text-blue-600 shadow-sm' : 'text-slate-500'}`}
              title="System Default"
            >
              <Monitor className="w-4 h-4" />
            </button>
            <button 
              onClick={() => setTheme('dark')}
              className={`p-2 rounded-lg transition-all ${theme === 'dark' ? 'bg-white dark:bg-slate-700 text-blue-600 shadow-sm' : 'text-slate-500'}`}
              title="Dark Mode"
