import React, { useMemo, useEffect, useState } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';
import { AlertTriangle, Car, CheckCircle, Clock, ShieldCheck } from 'lucide-react';
import { Violation, ViolationType } from '../types';
import { STORAGE_KEY_VIOLATIONS } from '../constants';

const Dashboard: React.FC = () => {
  const [violations, setViolations] = useState<Violation[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(document.documentElement.classList.contains('dark'));

  useEffect(() => {
    const observer = new MutationObserver(() => {
      setIsDarkMode(document.documentElement.classList.contains('dark'));
    });
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });

    const loadData = () => {
      const data = localStorage.getItem(STORAGE_KEY_VIOLATIONS);
      if (data) setViolations(JSON.parse(data));
    };
    loadData();
    window.addEventListener('storage', loadData);
    return () => {
      window.removeEventListener('storage', loadData);
      observer.disconnect();
    };
  }, []);

  const stats = useMemo(() => {
    const total = violations.length;
    const pending = violations.filter(v => v.status === 'pending').length;
    const verified = violations.filter(v => v.status === 'verified').length;
    const rejected = violations.filter(v => v.status === 'rejected').length;

    const typeBreakdown = Object.values(ViolationType).map(type => ({
      name: type,
      value: violations.filter(v => v.violationType === type).length
    })).filter(item => item.value > 0);

    return { total, pending, verified, rejected, typeBreakdown };
  }, [violations]);

  const PIE_COLORS = ['#2563eb', '#7c3aed', '#db2777', '#ea580c', '#ca8a04', '#16a34a'];
  const textColor = isDarkMode ? '#94a3b8' : '#64748b';
  const gridColor = isDarkMode ? '#1e293b' : '#f1f5f9';

  if (violations.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm animate-in fade-in duration-500">
        <div className="w-24 h-24 bg-blue-50 dark:bg-blue-900/20 rounded-full flex items-center justify-center mb-6 border border-blue-100 dark:border-blue-900/30">
          <ShieldCheck className="w-12 h-12 text-blue-600 dark:text-blue-400" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Operational Dashboard</h2>
        <p className="text-slate-500 dark:text-slate-400 mt-2 max-w-md text-center px-4">
          No traffic data recorded yet. Once violations are processed in the Media Lab, real-time analytics will appear here.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={<AlertTriangle className="text-amber-600 dark:text-amber-500" />} 
          title="Total Violations" 
          value={stats.total} 
          trend="Live Registry"
        />
        <StatCard 
          icon={<Clock className="text-blue-600 dark:text-blue-400" />} 
          title="Pending Review" 
          value={stats.pending} 
          trend="Needs Attention"
        />
        <StatCard 
          icon={<CheckCircle className="text-green-600 dark:text-green-500" />} 
          title="Verified" 
          value={stats.verified} 
          trend="Enforced Cases"
        />
        <StatCard 
          icon={<Car className="text-slate-600 dark:text-slate-400" />} 
          title="Unique Vehicles" 
          value={new Set(violations.map(v => v.vehicleNumber)).size} 
          trend="Distinct IDs"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Violations by Type</h3>
          <div className="h-80">
            {stats.typeBreakdown.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats.typeBreakdown}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={gridColor} />
                  <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 600, fill: textColor}} stroke={textColor} />
                  <YAxis tick={{fontSize: 12, fill: textColor}} stroke={textColor} />
                  <Tooltip 
                    cursor={{fill: isDarkMode ? '#1e293b' : '#f8fafc'}}
                    contentStyle={{
                      borderRadius: '16px', 
                      border: 'none', 
                      boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)',
                      backgroundColor: isDarkMode ? '#0f172a' : '#ffffff',
                      color: isDarkMode ? '#f8fafc' : '#1e293b'
                    }}
                  />
                  <Bar dataKey="value" fill="#2563eb" radius={[6, 6, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 italic">Insufficient data for breakdown</div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Verification Distribution</h3>
          <div className="h-80 flex items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={[
                    { name: 'Pending', value: stats.pending },
                    { name: 'Verified', value: stats.verified },
                    { name: 'Rejected', value: stats.rejected },
                  ].filter(d => d.value > 0)}
                  innerRadius={70}
                  outerRadius={100}
                  paddingAngle={8}
                  dataKey="value"
                  stroke="none"
                >
                  {PIE_COLORS.map((color, index) => (
                    <Cell key={`cell-${index}`} fill={color} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{
                    borderRadius: '12px',
                    border: 'none',
                    backgroundColor: isDarkMode ? '#0f172a' : '#ffffff',
                    color: isDarkMode ? '#f8fafc' : '#1e293b'
                  }}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="w-1/3 space-y-4 pr-4 shrink-0">
              <LegendItem color={PIE_COLORS[0]} label="Pending" value={stats.pending} />
              <LegendItem color={PIE_COLORS[1]} label="Verified" value={stats.verified} />
              <LegendItem color={PIE_COLORS[2]} label="Rejected" value={stats.rejected} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, title: string, value: number, trend: string }> = ({ icon, title, value, trend }) => (
  <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 hover:border-blue-100 dark:hover:border-blue-900 transition-colors">
    <div className="flex justify-between items-start mb-4">
      <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">{icon}</div>
      <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 bg-slate-50 dark:bg-slate-800 px-2.5 py-1 rounded-lg border border-slate-100 dark:border-slate-700 uppercase tracking-widest">{trend}</span>
    </div>
    <p className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wider">{title}</p>
    <h4 className="text-3xl font-bold text-slate-900 dark:text-white mt-1">{value}</h4>
  </div>
);

const LegendItem: React.FC<{ color: string, label: string, value: number }> = ({ color, label, value }) => (
  <div className="flex flex-col">
    <div className="flex items-center gap-2">
      <div className="w-2 h-2 rounded-full" style={{ backgroundColor: color }}></div>
      <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-tight">{label}</span>
    </div>
    <span className="text-xl font-bold text-slate-900 dark:text-white ml-4 leading-tight">{value}</span>
  </div>
);

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { Search, Filter, FileDown, MoreVertical, Check, X, Eye, History } from 'lucide-react';
import { Violation, ViolationType } from '../types';
import { STORAGE_KEY_VIOLATIONS } from '../constants';
import { formatDateTime, exportToCSV } from '../utils/helpers';

interface ViolationHistoryProps {
  isAdmin: boolean;
}

const ViolationHistory: React.FC<ViolationHistoryProps> = ({ isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [violations, setViolations] = useState<Violation[]>([]);

  useEffect(() => {
    const loadViolations = () => {
      const data = localStorage.getItem(STORAGE_KEY_VIOLATIONS);
      if (data) {
        try {
          setViolations(JSON.parse(data));
        } catch (e) {
          console.error("Failed to parse violations", e);
          setViolations([]);
        }
      }
    };
    loadViolations();
    window.addEventListener('storage', loadViolations);
    return () => window.removeEventListener('storage', loadViolations);
  }, []);

  const filteredViolations = useMemo(() => {
    return violations.filter(v => {
      const matchesSearch = v.vehicleNumber.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesFilter = filterType === 'all' || v.violationType === filterType;
      return matchesSearch && matchesFilter;
    });
  }, [violations, searchTerm, filterType]);

  const handleUpdateStatus = (id: string, status: 'verified' | 'rejected') => {
    const updated = violations.map(v => v.id === id ? { ...v, status } : v);
    setViolations(updated);
    localStorage.setItem(STORAGE_KEY_VIOLATIONS, JSON.stringify(updated));
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
      <div className="p-6 border-b border-slate-50 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search by vehicle number..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition dark:text-white"
          />
        </div>

        <div className="flex items-center gap-3">
          <div className="relative">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <select 
              className="pl-10 pr-8 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm appearance-none focus:outline-none transition dark:text-white"
              value={filterType}
              onChange={(e) => setFilterType(e.target.value)}
            >
              <option value="all">All Types</option>
              {Object.values(ViolationType).map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>

          <button 
            onClick={() => exportToCSV(violations)}
            className="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-800 text-white rounded-xl text-sm font-semibold hover:bg-slate-800 dark:hover:bg-slate-700 transition"
          >
            <FileDown className="w-4 h-4" />
            Export CSV
          </button>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wider border-b border-slate-100 dark:border-slate-800">
            <tr>
              <th className="px-6 py-4">Vehicle Details</th>
              <th className="px-6 py-4">Violation</th>
              <th className="px-6 py-4">Time & Location</th>
              <th className="px-6 py-4">Status</th>
